#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        char C[N + 1];
        scanf("%s", C);
        int minutes = 0;
        for (int i = 0; i < N;) {
            if (C[i] == 'R') {
                minutes++;
                for (int j = 1; j < K && i + j < N; j++) {
                    if (C[i + j] == 'R') C[i + j] = 'G';
                    else C[i + j] = 'R';
                }
                i += K;
            } else i++;
        }
        printf("%d\n", minutes);
    }
    return 0;
}

