code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            String C = sc.next();
            int minutes = 0;
            for (int i = 0; i < N;) {
                if (C.charAt(i) == 'R') {
                    minutes++;
                    for (int j = 1; j < K && i + j < N; j++) {
                        if (C.charAt(i + j) == 'R') C = C.substring(0, i + j) + 'G' + C.substring(i + j + 1);
                        else C = C.substring(0, i + j) + 'R' + C.substring(i + j + 1);
                    }
                    i += K;
                } else i++;
            }
            System.out.println(minutes);
        }
    }
}

